import { useEffect, useState } from "react";

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

function Crypto() {
  const [cryptodata, setCryptodata] = useState([]);

  useEffect(() => {
    let cancelled = false;

    async function fetchCoins() {
      const coins = ["bitcoin", "ethereum", "XRP"];
      const results = [];

      for (const coin of coins) {
        // small spacing to avoid rate limits
        await sleep(1200);

        // basic retry for 429
        for (let attempt = 0; attempt < 3; attempt++) {
          const res = await fetch(
            `https://api.coingecko.com/api/v3/coins/${coin}/market_chart?vs_currency=usd&days=7&interval=daily`
          );

          if (res.status === 429) {
            await sleep(2000 * (attempt + 1));
            continue;
          }

          if (!res.ok) {
            throw new Error(`Fetch failed for ${coin}: ${res.status}`);
          }

          const json = await res.json();
          results.push({ coin, data: json });
          break;
        }
      }

      if (!cancelled) setCryptodata(results);
    }

    fetchCoins().catch(console.error);

    return () => {
      cancelled = true;
    };
  }, []);

  console.log(cryptodata);

  return <></>;
}

export default Crypto;
